// GitOps Flux compliance and drift monitoring KQL
// Run in Log Analytics workspace connected to Arc K8s cluster via Container Insights

// 1. FluxConfiguration sync status across all clusters
// (Requires Azure Policy compliance data — not from Log Analytics directly)
// Use Resource Graph for cross-cluster Flux status:
// az graph query -q "Resources | where type == 'microsoft.kubernetesconfiguration/fluxconfigurations'"

// 2. Kubernetes events: Flux reconciliation failures
KubeEvents
| where TimeGenerated > ago(1h)
| where Source has 'flux'
| where Type == 'Warning'
| project TimeGenerated, ClusterName=ClusterId,
          Object=ObjectName, Message
| sort by TimeGenerated desc

// 3. Drift detection: resources modified outside of GitOps (kubectl apply by hand)
// Flux sets 'app.kubernetes.io/managed-by=Helm' or a flux owner annotation.
// Resources without these labels in Flux-managed namespaces indicate drift.
KubePodInventory
| where TimeGenerated > ago(30m)
| where Namespace in ('default', 'production', 'staging')
| where Labels !contains 'app.kubernetes.io/managed-by'
| project TimeGenerated, ClusterId, Namespace, PodName=Name, ContainerImage
| sort by TimeGenerated desc

// 4. Container restarts in Flux-managed namespaces (indicates bad image or config drift)
KubePodInventory
| where TimeGenerated > ago(1h)
| where PodStatus == 'Running'
| where RestartCount > 3
| project ClusterId, Namespace, PodName=Name, ContainerName, RestartCount, ContainerImage
| sort by RestartCount desc

// 5. Flux controller pod health (critical pods in flux-system namespace)
KubePodInventory
| where TimeGenerated > ago(10m)
| where Namespace == 'flux-system'
| where PodStatus != 'Running'
| project TimeGenerated, ClusterId, PodName=Name, Status=PodStatus, RestartCount
| sort by TimeGenerated desc

// 6. Alert rule: Flux kustomize-controller unable to apply (sync failure)
// Set this up as an Azure Monitor alert with 5-minute evaluation window
ContainerLog
| where TimeGenerated > ago(5m)
| where ContainerID has 'kustomize-controller'
| where LogEntry has 'failed to apply' or LogEntry has 'reconciliation failed'
| project TimeGenerated, ClusterId=ClusterName, Message=LogEntry
| sort by TimeGenerated desc
